#![no_std]
#![no_main]
#![doc = include_str!("../README.md")]

#[macro_use]
extern crate axlog;
extern crate alloc;
extern crate axruntime;

use alloc::{
    format,
    string::{String, ToString},
    vec,
    vec::Vec,
};

mod entry;
mod mm;
mod syscall;

#[unsafe(no_mangle)]
fn main() {
    // Create a init process
    axprocess::Process::new_init(axtask::current().id().as_u64() as _).build();

    let testcases = option_env!("AX_TESTCASES_LIST")
        .unwrap_or_else(|| "Please specify the testcases list by making user_apps")
        .split(',')
        .filter(|&x| !x.is_empty());

    for testcase in testcases {
        let Some(args) = shlex::split(testcase) else {
            error!("Failed to parse testcase: {:?}", testcase);
            continue;
        };
        if args.is_empty() {
            continue;
        }
        info!("Running user task: {:?}", args);

        let envs = testcase_envs(&args);
        let exit_code = entry::run_user_app(&args, &envs);
        info!("User task {:?} exited with code: {:?}", args, exit_code);
    }
}

/// 根据测例入口路径推导 libc 根目录。
fn libc_root(args: &[String]) -> Option<&'static str> {
    let path = args.first()?;
    if path.starts_with("/glibc/") {
        Some("/glibc")
    } else if path.starts_with("/musl/") {
        Some("/musl")
    } else {
        None
    }
}

/// 为 oscomp 测例生成基础环境变量。
fn testcase_envs(args: &[String]) -> Vec<String> {
    // PWD 与 entry::run_user_app 中设置的当前目录保持一致。
    let cwd = args
        .first()
        .and_then(|path| path.rsplit_once('/'))
        .map_or("/", |(dir, _)| if dir.is_empty() { "/" } else { dir });

    let root = libc_root(args);
    let (path_env, shell_env) = match root {
        Some(root) => (
            format!("PATH=/bin:/usr/bin:/usr/local/bin:{}", root),
            format!("SHELL={}/busybox", root),
        ),
        None => (
            "PATH=/bin:/usr/bin:/usr/local/bin".to_string(),
            "SHELL=/bin/sh".to_string(),
        ),
    };

    let mut envs = vec![
        path_env,
        "HOME=/".to_string(),
        format!("PWD={}", cwd),
        shell_env,
    ];

    if let Some(root) = root {
        // 测试镜像按 libc 根目录存放动态库，给动态链接器提供与入口一致的库搜索路径。
        envs.push(format!("LD_LIBRARY_PATH={}/lib", root));
    }

    envs
}

use alloc::{string::String, sync::Arc};
use axfs::{api::set_current_dir, CURRENT_DIR, CURRENT_DIR_PATH};
use axhal::arch::UspaceContext;
use axprocess::{init_proc, Pid};
use axsignal::Signo;
use axsync::Mutex;
use starry_api::{
    build_exec_plan,
    file::{FD_LIMIT, FD_TABLE},
};
use starry_core::{
    mm::{copy_from_kernel, load_user_app, map_trampoline, new_user_aspace_empty},
    task::{add_thread_to_table, new_user_task, ProcessData, TaskExt, ThreadData},
};

pub fn run_user_app(args: &[String], envs: &[String]) -> Option<i32> {
    let mut uspace = new_user_aspace_empty()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            map_trampoline(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");

    let exe_path = args[0].clone();
    let plan = build_exec_plan(exe_path.clone(), args.to_vec(), &exe_path)
        .unwrap_or_else(|e| panic!("Failed to build exec plan: {}", e));

    let (dir, name) = plan
        .exe_path
        .rsplit_once('/')
        .unwrap_or(("", plan.exe_path.as_str()));
    set_current_dir(dir).expect("Failed to set current dir");

    let (entry_vaddr, ustack_top) = load_user_app(&mut uspace, &plan.image_path, &plan.argv, envs)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));

    let uctx = UspaceContext::new(entry_vaddr.into(), ustack_top, 2333);

    let mut task = new_user_task(name, uctx, None);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let process_data = ProcessData::new(
        plan.exe_path,
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        Some(Signo::SIGCHLD),
    );

    FD_TABLE
        .deref_from(&process_data.ns)
        .init_new(FD_TABLE.copy_inner());
    FD_LIMIT
        .deref_from(&process_data.ns)
        .init_new(FD_LIMIT.copy_inner());
    CURRENT_DIR
        .deref_from(&process_data.ns)
        .init_new(CURRENT_DIR.copy_inner());
    CURRENT_DIR_PATH
        .deref_from(&process_data.ns)
        .init_new(CURRENT_DIR_PATH.copy_inner());

    let tid = task.id().as_u64() as Pid;
    let process = init_proc().fork(tid).data(process_data).build();

    let thread = process
        .new_thread(tid)
        .data(ThreadData::new(process.data().unwrap()))
        .build();
    add_thread_to_table(&thread);

    task.init_task_ext(TaskExt::new(thread));

    let task = axtask::spawn_task(task);

    let exit_code = task.join();
    reap_init_child_zombies();
    exit_code
}

fn reap_init_child_zombies() {
    loop {
        let zombies = init_proc()
            .children()
            .into_iter()
            .filter(|process| process.is_zombie())
            .collect::<alloc::vec::Vec<_>>();

        if zombies.is_empty() {
            break;
        }

        // 当前启动模型没有常驻用户态 init 执行 wait，内核入口线程需要承担 reaper 职责，回收 init 名下的 zombie。
        for process in zombies {
            process.free();
        }
    }
}

use axhal::{
    mem::VirtAddr,
    paging::MappingFlags,
    trap::{register_trap_handler, PAGE_FAULT},
};
use axsignal::{SignalInfo, Signo};
use axtask::{current, TaskExtRef};
use linux_raw_sys::general::{SEGV_ACCERR, SIGSEGV};
use starry_api::do_exit;
use starry_core::mm::is_accessing_user_memory;

#[register_trap_handler(PAGE_FAULT)]
fn handle_page_fault(vaddr: VirtAddr, access_flags: MappingFlags, is_user: bool) -> bool {
    // 可恢复缺页是用户地址空间按需映射的一部分，避免污染测评串口输出。
    debug!(
        "Page fault at {:#x}, access_flags: {:#x?}",
        vaddr, access_flags
    );
    if !is_user && !is_accessing_user_memory() {
        return false;
    }

    let curr = current();
    if !curr
        .task_ext()
        .process_data()
        .aspace
        .lock()
        .handle_page_fault(vaddr, access_flags)
    {
        if is_user {
            // 用户态访问受保护页时应交给 SIGSEGV handler，而不是直接结束进程。
            curr.task_ext()
                .thread_data()
                .signal
                .send_signal(SignalInfo::new(Signo::SIGSEGV, SEGV_ACCERR as _));
            return true;
        }
        warn!(
            "{} ({:?}): segmentation fault at {:#x}, exit!",
            curr.id_name(),
            curr.task_ext().thread,
            vaddr
        );
        do_exit(SIGSEGV as _, true);
    }
    true
}

