const SHEBANG_MAX_LEN: usize = 256;
const SHEBANG_RECURSION_LIMIT: usize = 4;
const LMBENCH_BUILD_PREFIX: &str = "/code/lmbench_src/bin/build/";

pub struct ExecPlan {
    pub image_path: String,
    pub argv: Vec<String>,
    pub exe_path: String,
    pub task_name: String,
}

impl ExecPlan {
    fn from_request(exec_path: String, args: Vec<String>, current_exe: &str) -> LinuxResult<Self> {
        let proc_self_exe = exec_path == "/proc/self/exe";
        let exec_path = resolve_proc_self_exe(exec_path, current_exe);
        let exec_path = resolve_lmbench_build_path(exec_path, current_exe);
        let mut plan = if proc_self_exe {
            Self::new_preserve_argv(exec_path.clone(), args)
        } else {
            Self::new(exec_path.clone(), args)
        };

        if axfs::api::metadata(&exec_path).is_err() {
            plan.apply_busybox_binary_if_needed(&exec_path, current_exe);
            plan.apply_busybox_alias_if_needed(&exec_path, current_exe);
        }

        plan.expand_shebangs(current_exe)?;
        Ok(plan)
    }

    fn new(exec_path: String, args: Vec<String>) -> Self {
        let argv = if args.is_empty() {
            let mut fallback = Vec::new();
            fallback.push(exec_path.clone());
            fallback
        } else {
            let mut fixed = args;
            // glibc 动态链接器会用 argv[0] 计算 $ORIGIN，相对路径会触发断言。
            fixed[0] = exec_path.clone();
            fixed
        };

        let task_name = task_name_from_path(&exec_path);

        Self {
            image_path: exec_path.clone(),
            argv,
            exe_path: exec_path,
            task_name,
        }
    }

    fn new_preserve_argv(exec_path: String, args: Vec<String>) -> Self {
        let argv = if args.is_empty() {
            vec![exec_path.clone()]
        } else {
            args
        };
        let task_name = task_name_from_path(&exec_path);

        Self {
            image_path: exec_path.clone(),
            argv,
            exe_path: exec_path,
            task_name,
        }
    }

    fn apply_busybox_binary_if_needed(&mut self, exec_path: &str, current_exe: &str) {
        if exec_path != "/busybox" && exec_path != "/bin/busybox" {
            return;
        }

        let Some(root) = libc_root_from_context(exec_path, current_exe) else {
            return;
        };

        let busybox_path = format!("{}/busybox", root);
        if self.argv.is_empty() {
            self.argv.push(busybox_path.clone());
        } else {
            self.argv[0] = busybox_path.clone();
        }
        self.image_path = busybox_path.clone();
        self.exe_path = busybox_path;
        self.task_name = String::from("busybox");
    }

    fn apply_busybox_alias_if_needed(&mut self, exec_path: &str, current_exe: &str) {
        let Some(alias) = resolve_busybox_applet_alias(exec_path, current_exe) else {
            return;
        };

        debug!(
            "sys_execve: resolved busybox applet alias: {} -> {} {}",
            exec_path, alias.busybox_path, alias.applet
        );

        self.apply_busybox_alias(alias);
    }

    fn apply_busybox_alias(&mut self, alias: BusyboxAppletAlias) {
        let mut alias_args = Vec::new();
        alias_args.push(alias.busybox_path.clone());
        alias_args.push(alias.applet.clone());
        alias_args.extend(self.argv.iter().skip(1).cloned());

        self.image_path = alias.busybox_path.clone();
        self.argv = alias_args;
        self.exe_path = alias.busybox_path;
        self.task_name = alias.applet;
    }

    fn expand_shebangs(&mut self, current_exe: &str) -> LinuxResult {
        for _ in 0..SHEBANG_RECURSION_LIMIT {
            let Ok(file_data) = axfs::api::read(self.image_path.as_str()) else {
                return Ok(());
            };

            let Some((interpreter, interpreter_arg)) = parse_shebang(&file_data)? else {
                if self.apply_shell_script_fallback(current_exe) {
                    continue;
                }
                return Ok(());
            };

            let script_path = self.image_path.clone();
            let interpreter = resolve_shebang_interpreter(&script_path, &interpreter, current_exe);

            let mut argv = interpreter.argv_prefix;
            if let Some(arg) = interpreter_arg {
                argv.push(arg);
            }
            argv.push(script_path);
            argv.extend(self.argv.iter().skip(1).cloned());

            self.image_path = interpreter.image_path;
            self.argv = argv;
        }

        Err(LinuxError::ELOOP)
    }

    fn apply_shell_script_fallback(&mut self, current_exe: &str) -> bool {
        if !self.image_path.ends_with(".sh") {
            return false;
        }

        let script_path = self.image_path.clone();
        // 部分测评脚本没有 shebang；这里按 shell 脚本意图展开，避免架构间 BusyBox 回退行为不一致。
        let interpreter = resolve_shebang_interpreter(&script_path, "/bin/sh", current_exe);
        let mut argv = interpreter.argv_prefix;
        argv.push(script_path);
        argv.extend(self.argv.iter().skip(1).cloned());

        self.image_path = interpreter.image_path;
        self.argv = argv;
        true
    }
}

pub fn build_exec_plan(
    exec_path: String,
    args: Vec<String>,
    current_exe: &str,
) -> LinuxResult<ExecPlan> {
    ExecPlan::from_request(exec_path, args, current_exe)
}

fn resolve_proc_self_exe(exec_path: String, current_exe: &str) -> String {
    if exec_path == "/proc/self/exe" {
        // BusyBox shell 在 ENOEXEC 回退路径中会重新 exec /proc/self/exe；这里映射到当前 ELF。
        current_exe.to_string()
    } else {
        exec_path
    }
}

fn resolve_lmbench_build_path(exec_path: String, current_exe: &str) -> String {
    let Some(name) = exec_path.strip_prefix(LMBENCH_BUILD_PREFIX) else {
        return exec_path;
    };
    let Some(root) = libc_root_from_context(&exec_path, current_exe) else {
        return exec_path;
    };

    let candidate = format!("{}/{}", root, name);
    // lmbench 的 hello 脚本保留了构建机绝对路径；测评镜像中对应 ELF 放在 libc 根目录下。
    if axfs::api::metadata(&candidate).is_ok() {
        candidate
    } else {
        exec_path
    }
}

fn parse_shebang(file_data: &[u8]) -> LinuxResult<Option<(String, Option<String>)>> {
    if !file_data.starts_with(b"#!") {
        return Ok(None);
    }

    let head = &file_data[2..file_data.len().min(SHEBANG_MAX_LEN)];
    let pos = head.iter().position(|c| *c == b'\n').unwrap_or(head.len());
    let line = core::str::from_utf8(&head[..pos]).map_err(|_| LinuxError::EINVAL)?;

    let mut parts = line
        .splitn(2, |c: char| c.is_ascii_whitespace())
        .map(|s| s.trim_ascii())
        .filter(|s| !s.is_empty());
    let interpreter = parts.next().ok_or(LinuxError::EINVAL)?;
    let interpreter_arg = parts.next().map(ToString::to_string);

    Ok(Some((interpreter.to_string(), interpreter_arg)))
}

fn libc_root_from_context(script_path: &str, current_exe: &str) -> Option<&'static str> {
