struct PseudoInodes {
    paths: RwLock<BTreeMap<String, u64>>,
}

impl PseudoInodes {
    const fn new() -> Self {
        Self {
            paths: RwLock::new(BTreeMap::new()),
        }
    }

    fn get(&self, path: &str) -> u64 {
        if let Some(ino) = self.paths.read().get(path).copied() {
            return ino;
        }

        let mut paths = self.paths.write();
        if let Some(ino) = paths.get(path).copied() {
            return ino;
        }

        let ino = paths.len() as u64 + 2;
        paths.insert(path.to_string(), ino);
        ino
    }
}

static PSEUDO_INODES: PseudoInodes = PseudoInodes::new();

// axfs 当前没有向 Linux 兼容层暴露真实 inode。这里给每个路径分配稳定小正数，
// 既避免动态链接器把不同 DSO 误判为同一文件，也避免 basic-musl 打印负 inode。
fn pseudo_inode(path: &str) -> u64 {
    PSEUDO_INODES.get(path)
}

