enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

const RING_BUFFER_SIZE: usize = 256;
const PIPE_TRACE_LIMIT: usize = 200;
const PIPE_WAIT_SLICE: Duration = Duration::from_millis(1);

static PIPE_TRACE_COUNT: AtomicUsize = AtomicUsize::new(0);

fn trace_pipe_enabled() -> bool {
    option_env!("OSKERNEL_TRACE_PIPE").is_some()
}

fn trace_pipe_event(
    event: &str,
    readable: bool,
    request_len: usize,
    done_len: usize,
    read_avail: usize,
    write_avail: usize,
    refs: usize,
) {
    if !trace_pipe_enabled() {
        return;
    }
    let seq = PIPE_TRACE_COUNT.fetch_add(1, Ordering::Relaxed);
    if seq >= PIPE_TRACE_LIMIT {
        return;
    }
    warn!(
        "[pipe-trace] seq={} task={} event={} end={} request_len={} done_len={} read_avail={} write_avail={} refs={}",
        seq,
        axtask::current().id_name(),
        event,
        if readable { "read" } else { "write" },
        request_len,
        done_len,
        read_avail,
        write_avail,
        refs
    );
}

fn has_pending_signal() -> bool {
    // 阻塞式 pipe 需要能被信号打断，lmbench 的 alarm 依赖该路径退出等待。
    !current()
        .task_ext()
        .thread_data()
        .signal
        .pending()
        .is_empty()
}

struct PipeRingBuffer {
    arr: [u8; RING_BUFFER_SIZE],
    head: usize,
    tail: usize,
    status: RingBufferStatus,
}

impl PipeRingBuffer {
    const fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
        }
    }

    fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }

    fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }

    /// Get the length of remaining data in the buffer
    const fn available_read(&self) -> usize {
        if matches!(self.status, RingBufferStatus::Empty) {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }

    /// Get the length of remaining space in the buffer
    const fn available_write(&self) -> usize {
        if matches!(self.status, RingBufferStatus::Full) {
            0
        } else {
            RING_BUFFER_SIZE - self.available_read()
        }
    }
}

struct PipeShared {
    buffer: Mutex<PipeRingBuffer>,
    read_wq: WaitQueue,
    write_wq: WaitQueue,
}

impl PipeShared {
    const fn new() -> Self {
        Self {
