pub enum Socket {
    Udp(Mutex<UdpSocket>),
    Tcp(Mutex<TcpSocket>),
}

struct UdpLoopbackPacket {
    port: u16,
    data: Vec<u8>,
    peer: SocketAddr,
}

struct TcpLoopbackConnection {
    port: u16,
    peer: SocketAddr,
}

// 当前 axnet/smoltcp 路径不负责把发往本机监听端口的数据绕回同一内核实例。
// 这里记录最小本地回环状态，用于支持 libctest 中同机 UDP/TCP socket 测例。
// 它不是完整协议栈：不处理并发连接语义、连接状态迁移、窗口、重传或真实网卡收发。
static UDP_BOUND_PORTS: Mutex<Vec<u16>> = Mutex::new(Vec::new());
static UDP_LOOPBACK_PACKETS: Mutex<Vec<UdpLoopbackPacket>> = Mutex::new(Vec::new());
static TCP_LISTEN_PORTS: Mutex<Vec<u16>> = Mutex::new(Vec::new());
static TCP_LOOPBACK_CONNECTIONS: Mutex<Vec<TcpLoopbackConnection>> = Mutex::new(Vec::new());

fn remember_udp_bound_port(port: u16) {
    if port == 0 {
        return;
    }

    let mut ports = UDP_BOUND_PORTS.lock();
    if !ports.contains(&port) {
        ports.push(port);
    }
}

fn has_local_udp_bound_port(port: u16) -> bool {
    UDP_BOUND_PORTS.lock().contains(&port)
}

fn push_udp_loopback_packet(port: u16, data: &[u8], peer: SocketAddr) {
    UDP_LOOPBACK_PACKETS.lock().push(UdpLoopbackPacket {
        port,
        data: data.to_vec(),
        peer,
    });
}

fn pop_udp_loopback_packet(port: u16) -> Option<UdpLoopbackPacket> {
    let mut packets = UDP_LOOPBACK_PACKETS.lock();
    let pos = packets.iter().position(|packet| packet.port == port)?;
    Some(packets.remove(pos))
}

fn remember_tcp_listen_port(port: u16) {
    if port == 0 {
        return;
    }

    let mut ports = TCP_LISTEN_PORTS.lock();
    if !ports.contains(&port) {
        ports.push(port);
    }
}

fn has_local_tcp_listen_port(port: u16) -> bool {
    TCP_LISTEN_PORTS.lock().contains(&port)
}

fn push_tcp_loopback_connection(port: u16, peer: SocketAddr) {
    TCP_LOOPBACK_CONNECTIONS
        .lock()
        .push(TcpLoopbackConnection { port, peer });
}

fn pop_tcp_loopback_connection(port: u16) -> Option<TcpLoopbackConnection> {
    let mut connections = TCP_LOOPBACK_CONNECTIONS.lock();
    let pos = connections
        .iter()
        .position(|connection| connection.port == port)?;
    Some(connections.remove(pos))
}

macro_rules! impl_socket {
    ($pub:vis fn $name:ident(&self $(,$arg:ident: $arg_ty:ty)*) -> $ret:ty) => {
        $pub fn $name(&self, $($arg: $arg_ty),*) -> $ret {
            match self {
                Socket::Udp(udpsocket) => Ok(udpsocket.lock().$name($($arg),*)?),
                Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().$name($($arg),*)?),
            }
        }
    };
}

impl Socket {
    pub fn recv(&self, buf: &mut [u8]) -> LinuxResult<usize> {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().recv_from(buf).map(|e| e.0)?),
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().recv(buf)?),
        }
    }

    pub fn sendto(&self, buf: &[u8], addr: SocketAddr) -> LinuxResult<usize> {
        match self {
            // Linux 允许未绑定 UDP socket 直接 sendto，此时内核会自动分配本地临时端口。
            Socket::Udp(udpsocket) => {
                let socket = udpsocket.lock();
                if socket.local_addr().is_err() {
                    socket.bind(SocketAddr::from(([0, 0, 0, 0], 0)))?;
                }
                if has_local_udp_bound_port(addr.port()) {
                    push_udp_loopback_packet(addr.port(), buf, socket.local_addr()?);
                    return Ok(buf.len());
                }
                Ok(socket.send_to(buf, addr)?)
            }
            Socket::Tcp(_) => Err(LinuxError::EISCONN),
        }
    }

    pub fn recvfrom(&self, buf: &mut [u8]) -> LinuxResult<(usize, Option<SocketAddr>)> {
        match self {
            Socket::Udp(udpsocket) => {
                let socket = udpsocket.lock();
                if let Ok(local_addr) = socket.local_addr() {
                    if let Some(packet) = pop_udp_loopback_packet(local_addr.port()) {
                        let len = packet.data.len().min(buf.len());
                        buf[..len].copy_from_slice(&packet.data[..len]);
                        return Ok((len, Some(packet.peer)));
                    }
                }
                Ok(socket.recv_from(buf).map(|res| (res.0, Some(res.1)))?)
            }
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().recv(buf).map(|res| (res, None))?),
        }
    }

    pub fn listen(&self) -> LinuxResult {
        match self {
            Socket::Udp(_) => Err(LinuxError::EOPNOTSUPP),
            Socket::Tcp(tcpsocket) => {
                let socket = tcpsocket.lock();
                socket.listen()?;
                remember_tcp_listen_port(socket.local_addr()?.port());
                Ok(())
            }
        }
    }

    pub fn accept(&self) -> LinuxResult<(TcpSocket, Option<SocketAddr>)> {
        match self {
            Socket::Udp(_) => Err(LinuxError::EOPNOTSUPP),
            Socket::Tcp(tcpsocket) => {
                let socket = tcpsocket.lock();
                // 对本机 connect/listen 的最小兼容：如果 connect 已经投递到本地监听端口，
                // accept 直接返回一个新 socket 和 peer 地址，避免底层网络栈等待外部包。
                if let Ok(local_addr) = socket.local_addr() {
                    if let Some(connection) = pop_tcp_loopback_connection(local_addr.port()) {
                        return Ok((TcpSocket::new(), Some(connection.peer)));
                    }
                }
                let accepted = socket.accept()?;
                let peer = accepted.peer_addr().ok();
                Ok((accepted, peer))
            }
        }
    }

    impl_socket!(pub fn send(&self, buf: &[u8]) -> LinuxResult<usize>);
    impl_socket!(pub fn poll(&self) -> LinuxResult<PollState>);
    impl_socket!(pub fn local_addr(&self) -> LinuxResult<SocketAddr>);
    impl_socket!(pub fn peer_addr(&self) -> LinuxResult<SocketAddr>);
    impl_socket!(pub fn shutdown(&self) -> LinuxResult);

    pub fn is_nonblocking(&self) -> bool {
        match self {
            Socket::Udp(udpsocket) => udpsocket.lock().is_nonblocking(),
            Socket::Tcp(tcpsocket) => tcpsocket.lock().is_nonblocking(),
        }
    }

    pub fn bind(&self, addr: SocketAddr) -> LinuxResult {
        match self {
            Socket::Udp(udpsocket) => {
                let socket = udpsocket.lock();
                socket.bind(addr)?;
                remember_udp_bound_port(socket.local_addr()?.port());
                Ok(())
            }
            Socket::Tcp(tcpsocket) => Ok(tcpsocket.lock().bind(addr)?),
        }
    }

    pub fn connect(&self, addr: SocketAddr) -> LinuxResult {
        match self {
            Socket::Udp(udpsocket) => Ok(udpsocket.lock().connect(addr)?),
            Socket::Tcp(tcpsocket) => {
                // 本地监听端口视为可连接，供同一测例进程内的 TCP loopback 用例继续运行。
                // 真实远端连接仍交给 axnet，错误码由底层网络栈返回。
                if has_local_tcp_listen_port(addr.port()) {
                    push_tcp_loopback_connection(addr.port(), SocketAddr::from(([0, 0, 0, 0], 0)));
                    return Ok(());
                }
                Ok(tcpsocket.lock().connect(addr)?)
            }
        }
    }
}

