use core::ffi::c_int;

use axerrno::{LinuxError, LinuxResult};
use axio::SeekFrom;
use linux_raw_sys::general::{__kernel_off_t, iovec};

use crate::{
    file::{get_file_like, File, FileLike},
    ptr::{UserConstPtr, UserPtr},
};

const SENDFILE_BUF_SIZE: usize = 4096;

/// Read data from the file indicated by `fd`.
///
/// Return the read size if success.
pub fn sys_read(fd: i32, buf: UserPtr<u8>, len: usize) -> LinuxResult<isize> {
    let buf = buf.get_as_mut_slice(len)?;
    debug!(
        "sys_read <= fd: {}, buf: {:p}, len: {}",
        fd,
        buf.as_ptr(),
        buf.len()
    );
    Ok(get_file_like(fd)?.read(buf)? as _)
}

pub fn sys_readv(fd: i32, iov: UserPtr<iovec>, iocnt: usize) -> LinuxResult<isize> {
    if !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_mut_slice(iocnt)?;
    let mut ret = 0;
    for iov in iovs {
        if iov.iov_len == 0 {
            continue;
        }
        let buf = UserPtr::<u8>::from(iov.iov_base as usize);
        let buf = buf.get_as_mut_slice(iov.iov_len as _)?;
        debug!(
            "sys_readv <= fd: {}, buf: {:p}, len: {}",
            fd,
            buf.as_ptr(),
            buf.len()
        );

        let read = get_file_like(fd)?.read(buf)?;
        ret += read as isize;

        if read < buf.len() {
            break;
        }
    }

    Ok(ret)
}

/// 从指定文件偏移读取数据，不改变文件描述符当前偏移。
pub fn sys_pread64(
    fd: i32,
    buf: UserPtr<u8>,
    len: usize,
    offset: __kernel_off_t,
) -> LinuxResult<isize> {
    if offset < 0 {
        return Err(LinuxError::EINVAL);
    }

    let buf = buf.get_as_mut_slice(len)?;
    debug!(
        "sys_pread64 <= fd: {}, buf: {:p}, len: {}, offset: {}",
        fd,
        buf.as_ptr(),
        buf.len(),
        offset
    );

    Ok(File::from_fd(fd)?.inner().read_at(offset as _, buf)? as _)
}

/// Write data to the file indicated by `fd`.
///
/// Return the written size if success.
pub fn sys_write(fd: i32, buf: UserConstPtr<u8>, len: usize) -> LinuxResult<isize> {
    let buf = buf.get_as_slice(len)?;
    debug!(
        "sys_write <= fd: {}, buf: {:p}, len: {}",
        fd,
        buf.as_ptr(),
        buf.len()
    );
    Ok(get_file_like(fd)?.write(buf)? as _)
}

pub fn sys_writev(fd: i32, iov: UserConstPtr<iovec>, iocnt: usize) -> LinuxResult<isize> {
    if !(0..=1024).contains(&iocnt) {
        return Err(LinuxError::EINVAL);
    }

    let iovs = iov.get_as_slice(iocnt)?;
    let mut ret = 0;
    for iov in iovs {
        if iov.iov_len == 0 {
            continue;
        }
        let buf = UserConstPtr::<u8>::from(iov.iov_base as usize);
        let buf = buf.get_as_slice(iov.iov_len as _)?;
        debug!(
            "sys_writev <= fd: {}, buf: {:p}, len: {}",
            fd,
            buf.as_ptr(),
            buf.len()
        );

        let written = get_file_like(fd)?.write(buf)?;
        ret += written as isize;

        if written < buf.len() {
            break;
        }
    }

    Ok(ret)
}

/// 在两个文件描述符之间复制数据。
///
/// `offset` 为空时使用输入文件当前位置；`offset` 非空时从指定偏移读取，并在返回前更新该偏移。
/// 返回值为实际复制的字节数。
pub fn sys_sendfile(
    out_fd: c_int,
    in_fd: c_int,
    offset: UserPtr<__kernel_off_t>,
    count: usize,
) -> LinuxResult<isize> {
    debug!(
        "sys_sendfile <= out_fd: {}, in_fd: {}, offset: {:p}, count: {}",
        out_fd,
        in_fd,
        offset.address().as_ptr(),
        count
    );

    let out_file = get_file_like(out_fd)?;
    let mut buf = [0u8; SENDFILE_BUF_SIZE];
    let mut copied = 0usize;

    // offset 为空时，sendfile 使用并推进输入文件自身的当前位置。
    if offset.is_null() {
        let in_file = get_file_like(in_fd)?;
        while copied < count {
            let len = core::cmp::min(buf.len(), count - copied);
            let read = in_file.read(&mut buf[..len])?;
            if read == 0 {
                break;
            }

            let written = out_file.write(&buf[..read])?;
            copied += written;
            if written < read {
                break;
            }
        }
        return Ok(copied as _);
    }

    // offset 非空时，sendfile 从指定偏移读取并回写 offset，不改变输入文件自身的当前位置。
    let offset = offset.get_as_mut()?;
    if *offset < 0 {
        return Err(LinuxError::EINVAL);
    }

    let in_file = File::from_fd(in_fd)?;
    let mut inner = in_file.inner();
    let original_pos = inner.seek(SeekFrom::Current(0))?;
    inner.seek(SeekFrom::Start(*offset as _))?;

    while copied < count {
        let len = core::cmp::min(buf.len(), count - copied);
        let read = inner.read(&mut buf[..len])?;
        if read == 0 {
            break;
        }

        let written = out_file.write(&buf[..read])?;
        copied += written;
        *offset += written as __kernel_off_t;
        if written < read {
            break;
        }
    }

    inner.seek(SeekFrom::Start(original_pos))?;
    Ok(copied as _)
}

pub fn sys_lseek(fd: c_int, offset: __kernel_off_t, whence: c_int) -> LinuxResult<isize> {
    debug!("sys_lseek <= {} {} {}", fd, offset, whence);
    let pos = match whence {
        0 => SeekFrom::Start(offset as _),
        1 => SeekFrom::Current(offset as _),
        2 => SeekFrom::End(offset as _),
        _ => return Err(LinuxError::EINVAL),
    };
    let off = File::from_fd(fd)?.inner().seek(pos)?;
    Ok(off as _)
}

