const O_EXEC: u32 = O_PATH;
const STATUS_FLAGS_MASK: u32 = 0b11 | O_APPEND | O_NONBLOCK | O_PATH;
const TMPFILE_COMPAT_PREFIX: &str = ".starry-tmpfile";
static TMPFILE_COUNTER: AtomicU64 = AtomicU64::new(0);

/// Convert open flags to [`OpenOptions`].
fn flags_to_options(flags: c_int, _mode: __kernel_mode_t) -> OpenOptions {
    let flags = flags as u32;
    let mut options = OpenOptions::new();
    match flags & 0b11 {
        O_RDONLY => options.read(true),
        O_WRONLY => options.write(true),
        _ => {
            options.read(true);
            options.write(true);
        }
    };
    if flags & O_APPEND != 0 {
        options.append(true);
    }
    if flags & O_TRUNC != 0 {
        options.truncate(true);
    }
    if flags & O_CREAT != 0 {
        options.create(true);
    }
    if flags & O_EXEC != 0 {
        //options.create_new(true);
        options.execute(true);
    }
    if flags & O_DIRECTORY != 0 {
        options.directory(true);
    }
    options
}

fn open_tmpfile_at(
    dirfd: c_int,
    path: &str,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    if (flags as u32 & 0b11) == O_RDONLY {
        return Err(LinuxError::EINVAL);
    }

    let dir_path = handle_file_path(dirfd, path)?;
    let seq = TMPFILE_COUNTER.fetch_add(1, Ordering::Relaxed);
    let pid = current().task_ext().thread.process().pid();
    let tid = current().id().as_u64();
    let dir = dir_path.as_str().trim_end_matches('/');
    let name = format!("{}/{}-{}-{}-{}", dir, TMPFILE_COMPAT_PREFIX, pid, tid, seq);

    // Linux 的 O_TMPFILE 创建未链接的匿名普通文件。当前 VFS 暂无匿名 inode，
    // 先在目标目录创建内部命名文件，以提供 tmpfile() 需要的读写和 seek 语义。
    let open_flags = (flags & !(O_TMPFILE as i32 | O_DIRECTORY as i32)) | O_CREAT as i32;
    let opts = flags_to_options(open_flags, mode);
    let file = axfs::fops::File::open(&name, &opts).map_err(LinuxError::from)?;
    Ok(add_file_like_with_status_flags(
        alloc::sync::Arc::new(File::new(file, name)),
        (open_flags as u32) & STATUS_FLAGS_MASK,
    )? as _)
}

/// Open or create a file.
/// fd: file descriptor
/// filename: file path to be opened or created
/// flags: open flags
/// mode: see man 7 inode
/// return new file descriptor if succeed, or return -1.
pub fn sys_openat(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    flags: i32,
    mode: __kernel_mode_t,
) -> LinuxResult<isize> {
    let path = path.get_as_str()?;
    if (flags as u32 & O_TMPFILE) == O_TMPFILE {
        return open_tmpfile_at(dirfd, path, flags, mode);
    }

    let opts = flags_to_options(flags, mode);
    debug!("sys_openat <= {} {} {:?}", dirfd, path, opts);

    // 对真实路径解析失败的绝对路径，尝试 BusyBox applet alias。
    let real_path = match handle_file_path(dirfd, path) {
        Ok(p) => {
            path_trace::event(
                "openat",
                Some(path),
                format_args!("dirfd={} flags={} resolved={} alias=none", dirfd, flags, p),
            );
            p
        }
        Err(err) => {
            path_trace::event(
                "openat",
                Some(path),
                format_args!("dirfd={} flags={} resolve=Err({:?})", dirfd, flags, err),
            );
            if path.starts_with('/') {
                let current_exe = current().task_ext().process_data().exe_path.read().clone();
                if let Some(alias) = resolve_busybox_applet_alias(path, &current_exe) {
                    path_trace::event(
                        "openat",
                        Some(path),
                        format_args!(
                            "dirfd={} flags={} current_exe={} alias={} applet={}",
                            dirfd, flags, current_exe, alias.busybox_path, alias.applet
                        ),
                    );
                    let alias_opts = OpenOptions::new().set_read(true);
                    let file = axfs::fops::File::open(&alias.busybox_path, &alias_opts)
                        .map_err(|e| LinuxError::from(e))?;
                    let fd = File::new(file, alias.busybox_path).add_to_fd_table()?;
                    return Ok(fd as _);
                }
            }
            return Err(err);
        }
    };

    let dir = if path.starts_with('/') || dirfd == AT_FDCWD {
        None
    } else {
        Some(Directory::from_fd(dirfd)?)
    };

    let path_is_dir = axfs::api::metadata(real_path.as_str())
        .map(|metadata| metadata.is_dir())
        .unwrap_or(false);
    if !opts.has_directory() && !path_is_dir {
        match dir.as_ref().map_or_else(
            || axfs::fops::File::open(path, &opts),
            |dir| dir.inner().open_file_at(path, &opts),
        ) {
            Err(AxError::IsADirectory) => {}
            r => {
                let file = File::new(r?, real_path.to_string());
                let fd = add_file_like_with_status_flags(
                    alloc::sync::Arc::new(file),
                    (flags as u32) & STATUS_FLAGS_MASK,
                )?;
                return Ok(fd as _);
            }
        }
    }

    let fd = Directory::new(
        dir.map_or_else(
            || axfs::fops::Directory::open_dir(path, &opts),
            |dir| dir.inner().open_dir_at(path, &opts),
        )?,
        real_path.to_string(),
    )
    .add_to_fd_table()?;
    Ok(fd as _)
}

