/// 兼容 `klogctl/syslog` 读取内核日志的最小语义。
///
/// Starry 当前没有对用户态开放的内核日志缓冲区，因此读取类命令返回空日志。
pub fn sys_syslog(cmd: c_int, buf: UserPtr<c_char>, len: c_int) -> LinuxResult<isize> {
    const SYSLOG_ACTION_CLOSE: c_int = 0;
    const SYSLOG_ACTION_OPEN: c_int = 1;
    const SYSLOG_ACTION_READ: c_int = 2;
    const SYSLOG_ACTION_READ_ALL: c_int = 3;
    const SYSLOG_ACTION_READ_CLEAR: c_int = 4;
    const SYSLOG_ACTION_CLEAR: c_int = 5;
    const SYSLOG_ACTION_CONSOLE_OFF: c_int = 6;
    const SYSLOG_ACTION_CONSOLE_ON: c_int = 7;
    const SYSLOG_ACTION_CONSOLE_LEVEL: c_int = 8;
    const SYSLOG_ACTION_SIZE_UNREAD: c_int = 9;
    const SYSLOG_ACTION_SIZE_BUFFER: c_int = 10;

    debug!("sys_syslog <= cmd: {}, len: {}", cmd, len);

    match cmd {
        SYSLOG_ACTION_CLOSE
        | SYSLOG_ACTION_OPEN
        | SYSLOG_ACTION_CLEAR
        | SYSLOG_ACTION_CONSOLE_OFF
        | SYSLOG_ACTION_CONSOLE_ON
        | SYSLOG_ACTION_CONSOLE_LEVEL => Ok(0),
        SYSLOG_ACTION_READ | SYSLOG_ACTION_READ_ALL | SYSLOG_ACTION_READ_CLEAR => {
            if len < 0 {
                return Err(LinuxError::EINVAL);
            }
            if len > 0 && buf.is_null() {
                return Err(LinuxError::EFAULT);
            }
            Ok(0)
        }
        SYSLOG_ACTION_SIZE_UNREAD | SYSLOG_ACTION_SIZE_BUFFER => Ok(0),
        _ => Err(LinuxError::EINVAL),
    }
}

/// 兼容 libc 线程库的用户态内存屏障请求。
///
/// 当前测评环境以单核 QEMU 为主，内核尚未实现跨 CPU 用户态屏障协议；这里接受常见命令并作为 no-op 返回。
pub fn sys_membarrier(cmd: c_int, flags: c_int, _cpu_id: c_int) -> LinuxResult<isize> {
    const MEMBARRIER_CMD_QUERY: c_int = 0;
    const MEMBARRIER_CMD_GLOBAL: c_int = 1;
    const MEMBARRIER_CMD_GLOBAL_EXPEDITED: c_int = 2;
    const MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED: c_int = 4;
    const MEMBARRIER_CMD_PRIVATE_EXPEDITED: c_int = 8;
    const MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED: c_int = 16;
    const MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE: c_int = 32;
    const MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE: c_int = 64;

    const SUPPORTED: c_int = MEMBARRIER_CMD_GLOBAL
        | MEMBARRIER_CMD_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE;

    if flags != 0 {
        return Err(LinuxError::EINVAL);
    }

    match cmd {
        MEMBARRIER_CMD_QUERY => Ok(SUPPORTED as _),
        MEMBARRIER_CMD_GLOBAL
        | MEMBARRIER_CMD_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_GLOBAL_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED
        | MEMBARRIER_CMD_PRIVATE_EXPEDITED_SYNC_CORE
        | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED_SYNC_CORE => Ok(0),
        _ => Err(LinuxError::EINVAL),
    }
}

