        RLIMIT_STACK => Ok(rlimit64 {
            rlim_cur: axconfig::plat::USER_STACK_SIZE as u64,
            rlim_max: axconfig::plat::USER_STACK_SIZE as u64,
        }),
        RLIMIT_NOFILE => {
            let limit = get_fd_limit();
            Ok(rlimit64 {
                rlim_cur: limit.cur as u64,
                rlim_max: limit.max as u64,
            })
        }
        RLIMIT_AS => Ok(rlimit64 {
            rlim_cur: axconfig::plat::USER_SPACE_SIZE as u64,
            rlim_max: axconfig::plat::USER_SPACE_SIZE as u64,
        }),
        // Starry 暂未强制限制这些资源，因此按宽松 Linux 环境返回 unlimited。
        // 该返回值仅表示当前不限制对应资源。
        RLIMIT_CPU | RLIMIT_FSIZE | RLIMIT_DATA | RLIMIT_CORE | RLIMIT_RSS | RLIMIT_NPROC
        | RLIMIT_MEMLOCK | RLIMIT_LOCKS | RLIMIT_SIGPENDING | RLIMIT_MSGQUEUE | RLIMIT_NICE
        | RLIMIT_RTPRIO | RLIMIT_RTTIME => Ok(rlimit64 {
            rlim_cur: infinity,
            rlim_max: infinity,
        }),
        _ => Err(LinuxError::EINVAL),
    }
}

