    if value == RLIM_INFINITY as u64 {
        Ok(AX_FILE_LIMIT)
    } else if value > AX_FILE_LIMIT as u64 {
        Err(LinuxError::EPERM)
    } else {
        Ok(value as usize)
    }
}

