    if limit.rlim_cur > limit.rlim_max {
        return Err(LinuxError::EINVAL);
    }

    match resource {
        RLIMIT_NOFILE => {
            let cur = normalize_nofile_limit(limit.rlim_cur)?;
            let max = normalize_nofile_limit(limit.rlim_max)?;
