    CLOCK_MONOTONIC_COARSE, CLOCK_REALTIME, CLOCK_REALTIME_COARSE, RUSAGE_CHILDREN, RUSAGE_SELF,
    RUSAGE_THREAD, SI_TIMER,
};
use spin::Mutex;
use starry_core::task::{get_process, time_stat_output};

use crate::{
    ptr::{nullable, UserConstPtr, UserPtr},
    signal::send_signal_process,
    time::TimeValueLike,
};

const ITIMER_REAL: i32 = 0;
const ITIMER_VIRTUAL: i32 = 1;
const ITIMER_PROF: i32 = 2;

#[repr(C)]
#[derive(Clone, Copy)]
pub struct Itimerval {
    it_interval: timeval,
    it_value: timeval,
}

impl Default for Itimerval {
    fn default() -> Self {
        Self {
            it_interval: duration_to_timeval(Duration::ZERO),
            it_value: duration_to_timeval(Duration::ZERO),
        }
    }
}

#[derive(Clone, Copy)]
struct TimerState {
    pid: Pid,
    which: i32,
    value: Itimerval,
    deadline_ns: u64,
}

static PROCESS_TIMERS: Mutex<Vec<TimerState>> = Mutex::new(Vec::new());

fn trace_timer_enabled() -> bool {
    option_env!("OSKERNEL_TRACE_TIMER").is_some()
}

fn check_timer_kind(which: i32) -> LinuxResult<()> {
    match which {
        ITIMER_REAL | ITIMER_VIRTUAL | ITIMER_PROF => Ok(()),
        _ => Err(LinuxError::EINVAL),
    }
}

fn timeval_to_duration(tv: timeval) -> LinuxResult<Duration> {
    if tv.tv_sec < 0 || tv.tv_usec < 0 || tv.tv_usec >= 1_000_000 {
        return Err(LinuxError::EINVAL);
    }
    Ok(Duration::new(tv.tv_sec as u64, tv.tv_usec as u32 * 1000))
}

fn duration_to_timeval(duration: Duration) -> timeval {
    timeval {
        tv_sec: duration.as_secs() as _,
        tv_usec: duration.subsec_micros() as _,
    }
}

fn is_timer_disarmed(value: Itimerval) -> bool {
    value.it_value.tv_sec == 0 && value.it_value.tv_usec == 0
}

fn timer_signal(which: i32) -> Signo {
    match which {
        ITIMER_REAL => Signo::SIGALRM,
        ITIMER_VIRTUAL => Signo::SIGVTALRM,
        ITIMER_PROF => Signo::SIGPROF,
        _ => Signo::SIGALRM,
    }
}

fn timer_deadline_ns(value: Itimerval) -> LinuxResult<u64> {
    if is_timer_disarmed(value) {
        Ok(0)
    } else {
        Ok(monotonic_time_nanos() + timeval_to_duration(value.it_value)?.as_nanos() as u64)
    }
}

fn schedule_process_timer_task(pid: Pid, which: i32, mut expected_deadline_ns: u64) {
    if expected_deadline_ns == 0 {
        return;
    }

    // 进程阻塞在 pipe 等系统调用时不会再次进入 syscall，因此需要内核任务异步触发 timer 信号。
    axtask::spawn(move || loop {
        let now = monotonic_time_nanos();
        if expected_deadline_ns > now {
            axtask::sleep(Duration::from_nanos(expected_deadline_ns - now));
        }

        let mut next_deadline_ns = 0;
        {
            let now = monotonic_time_nanos();
            let mut timers = PROCESS_TIMERS.lock();
            let Some(state) = timers
                .iter_mut()
                .find(|state| state.pid == pid && state.which == which)
            else {
                return;
            };
            if state.deadline_ns == 0 || state.deadline_ns != expected_deadline_ns {
                return;
            }
            if now < state.deadline_ns {
                continue;
            }

            let interval = timeval_to_duration(state.value.it_interval).unwrap_or_default();
            if interval.is_zero() {
                state.deadline_ns = 0;
                state.value.it_value = duration_to_timeval(Duration::ZERO);
            } else {
                state.deadline_ns = now + interval.as_nanos() as u64;
                state.value.it_value = state.value.it_interval;
                next_deadline_ns = state.deadline_ns;
            }
        }

        if trace_timer_enabled() {
            warn!(
                "[timer-trace] async expired pid={} which={} signal={:?}",
                pid,
                which,
                timer_signal(which)
            );
        }
        if let Ok(process) = get_process(pid) {
            let _ = send_signal_process(&process, SignalInfo::new(timer_signal(which), SI_TIMER));
        }

        if next_deadline_ns == 0 {
            return;
        }
        expected_deadline_ns = next_deadline_ns;
    });
}

fn update_process_timer(pid: Pid, which: i32, value: Itimerval) -> LinuxResult<()> {
    let deadline_ns = timer_deadline_ns(value)?;
    if trace_timer_enabled() {
        warn!(
            "[timer-trace] set pid={} which={} value={}.{:06} interval={}.{:06} deadline_ns={}",
            pid,
            which,
            value.it_value.tv_sec,
            value.it_value.tv_usec,
            value.it_interval.tv_sec,
            value.it_interval.tv_usec,
            deadline_ns
        );
    }
    let mut timers = PROCESS_TIMERS.lock();
    if let Some(state) = timers
        .iter_mut()
        .find(|state| state.pid == pid && state.which == which)
    {
        state.value = value;
        state.deadline_ns = deadline_ns;
    } else {
        timers.push(TimerState {
            pid,
            which,
            value,
            deadline_ns,
        });
    }
    drop(timers);
    schedule_process_timer_task(pid, which, deadline_ns);
    Ok(())
}

fn timer_snapshot(pid: Pid, which: i32) -> Itimerval {
    let now = monotonic_time_nanos();
    let timers = PROCESS_TIMERS.lock();
    timers
        .iter()
        .find(|state| state.pid == pid && state.which == which)
        .map(|state| {
            let mut value = state.value;
            value.it_value = if state.deadline_ns > now {
                duration_to_timeval(Duration::from_nanos(state.deadline_ns - now))
            } else {
                duration_to_timeval(Duration::ZERO)
            };
            value
        })
        .unwrap_or_default()
}

pub fn check_process_itimers() {
    let process = current().task_ext().thread.process().clone();
    let pid = process.pid();
    let now = monotonic_time_nanos();
    let mut expired = Vec::new();

    {
        let mut timers = PROCESS_TIMERS.lock();
        for state in timers.iter_mut().filter(|state| state.pid == pid) {
            if state.deadline_ns == 0 || now < state.deadline_ns {
                continue;
            }
            expired.push(state.which);

            let interval = timeval_to_duration(state.value.it_interval).unwrap_or_default();
            if interval.is_zero() {
                state.deadline_ns = 0;
                state.value.it_value = duration_to_timeval(Duration::ZERO);
            } else {
                state.deadline_ns = now + interval.as_nanos() as u64;
                state.value.it_value = state.value.it_interval;
            }
        }
    }

    for which in expired {
        if trace_timer_enabled() {
            warn!(
                "[timer-trace] expired pid={} which={} signal={:?}",
                pid,
                which,
                timer_signal(which)
            );
        }
        let _ = send_signal_process(&process, SignalInfo::new(timer_signal(which), SI_TIMER));
    }
}

pub fn sys_clock_gettime(
    clock_id: __kernel_clockid_t,
    ts: UserPtr<timespec>,
) -> LinuxResult<isize> {
    let now = match clock_id as u32 {
        CLOCK_REALTIME | CLOCK_REALTIME_COARSE => wall_time(),
        CLOCK_MONOTONIC | CLOCK_MONOTONIC_COARSE => monotonic_time(),
        _ => {
            warn!(
                "Called sys_clock_gettime for unsupported clock {}",
                clock_id
            );
            return Err(LinuxError::EINVAL);
        }
    };
    *ts.get_as_mut()? = timespec::from_time_value(now);
    Ok(0)
