//! 文件描述符就绪状态查询接口。
//!
//! 当前模块承载 poll/ppoll 这类跨文件类型的等待接口；

use core::time::Duration;

use axerrno::{LinuxError, LinuxResult};
use linux_raw_sys::general::{POLLIN, POLLNVAL, POLLOUT, pollfd, timespec};

use crate::{
    file::{Directory, File, Pipe, Socket, get_file_like},
    ptr::{UserConstPtr, UserPtr},
    time::TimeValueLike,
};

const FD_SET_BITS: usize = usize::BITS as usize;

fn trace_pselect_enabled() -> bool {
    option_env!("OSKERNEL_TRACE_PSELECT").is_some()
}

fn fd_set_word_count(nfds: usize) -> usize {
    nfds.div_ceil(FD_SET_BITS)
}

fn fd_is_set(words: &[usize], fd: usize) -> bool {
    words[fd / FD_SET_BITS] & (1usize << (fd % FD_SET_BITS)) != 0
}

fn fd_set(words: &mut [usize], fd: usize) {
    words[fd / FD_SET_BITS] |= 1usize << (fd % FD_SET_BITS);
}

fn fd_kind(fd: usize, file: &alloc::sync::Arc<dyn crate::file::FileLike>) -> &'static str {
    if fd == 0 {
        return "stdio";
    }
    if fd == 1 || fd == 2 {
        return "stdio";
    }

    let any = file.clone().into_any();
    if any.as_ref().is::<Pipe>() {
        "pipe"
    } else if any.as_ref().is::<File>() {
        "file"
    } else if any.as_ref().is::<Directory>() {
        "directory"
    } else if any.as_ref().is::<Socket>() {
        "socket"
    } else {
        "unknown"
    }
}

/// 将内核内部的可读写状态转换为用户态 `pollfd.revents` 位。
///
/// 返回调用者在 `events` 中关注的就绪事件。
fn poll_state_to_revents(events: i16, readable: bool, writable: bool) -> i16 {
    let mut revents = 0;
    if readable && events & (POLLIN as i16) != 0 {
        revents |= POLLIN as i16;
    }
    if writable && events & (POLLOUT as i16) != 0 {
        revents |= POLLOUT as i16;
    }
    revents
}

/// 查询一组文件描述符的当前就绪状态。
///
/// 当前实现只实现即时查询，未处理 `timeout` 等待和信号屏蔽；返回值为已就绪或出错的 fd 数量。
pub fn sys_ppoll(
    fds: UserPtr<pollfd>,
    nfds: usize,
    _timeout: UserConstPtr<timespec>,
    _sigmask: UserConstPtr<u8>,
    _sigsetsize: usize,
) -> LinuxResult<isize> {
    // 就绪查询，不处理 timeout 等待和信号屏蔽。
    if nfds > 1024 {
        return Err(LinuxError::EINVAL);
    }

    let fds = fds.get_as_mut_slice(nfds)?;
    let mut ready = 0isize;
    for fd in fds {
        fd.revents = 0;
        if fd.fd < 0 {
            continue;
        }

        match get_file_like(fd.fd) {
            Ok(file) => {
                let state = file.poll()?;
                fd.revents = poll_state_to_revents(fd.events, state.readable, state.writable);
                if fd.revents != 0 {
                    ready += 1;
                }
            }
            Err(LinuxError::EBADF) => {
                fd.revents = POLLNVAL as i16;
                ready += 1;
            }
            Err(err) => return Err(err),
        }
    }

    Ok(ready)
}

/// 按当前 fd 状态实现最小 `pselect6` 语义。
///
/// 当前支持 fd_set 就绪查询和相对 timeout；暂不切换 signal mask，也没有等待队列唤醒机制。没有 fd 就绪时，带 timeout 的调用睡到超时后返回 0。
///
/// `timeout=0` 理论上应立即返回；这里额外让出一次 CPU，避免 lmbench 这类用户态 busy poll 在协作式调度下饿住写端任务。
pub fn sys_pselect6(
    nfds: usize,
    readfds: UserPtr<usize>,
    writefds: UserPtr<usize>,
    exceptfds: UserPtr<usize>,
    timeout: UserConstPtr<timespec>,
    _sigmask: UserConstPtr<u8>,
) -> LinuxResult<isize> {
    if trace_pselect_enabled() {
        trace_pselect_sets(nfds, readfds, writefds, exceptfds, timeout);
    }

    let ready = query_select_sets(nfds, readfds, writefds, exceptfds)?;
    if ready > 0 {
        return Ok(ready);
    }

    let Some(timeout) = pselect_timeout(timeout)? else {
        axtask::yield_now();
        return Ok(0);
    };
    if !timeout.is_zero() {
        axtask::sleep(timeout);
    } else {
        axtask::yield_now();
    }
    clear_select_sets(nfds, readfds, writefds, exceptfds)?;
    Ok(0)
}

fn pselect_timeout(timeout: UserConstPtr<timespec>) -> LinuxResult<Option<Duration>> {
    if timeout.is_null() {
        return Ok(None);
    }

    let timeout = timeout.get_as_ref()?;
    if timeout.tv_sec < 0 || timeout.tv_nsec < 0 || timeout.tv_nsec >= 1_000_000_000 {
        return Err(LinuxError::EINVAL);
    }

    Ok(Some(timeout.to_time_value()))
}

fn query_select_sets(
    nfds: usize,
    readfds: UserPtr<usize>,
    writefds: UserPtr<usize>,
    exceptfds: UserPtr<usize>,
) -> LinuxResult<isize> {
    if nfds > 1024 {
        return Err(LinuxError::EINVAL);
    }

    let words = fd_set_word_count(nfds);
    let read_in = fd_set_snapshot_result(readfds, words)?;
    let write_in = fd_set_snapshot_result(writefds, words)?;
    let except_in = fd_set_snapshot_result(exceptfds, words)?;
    let mut read_ready = alloc::vec![0usize; words];
    let mut write_ready = alloc::vec![0usize; words];
    let mut except_ready = alloc::vec![0usize; words];
    let mut ready = 0isize;

    for fd in 0..nfds {
        let want_read = read_in.as_ref().is_some_and(|set| fd_is_set(set, fd));
        let want_write = write_in.as_ref().is_some_and(|set| fd_is_set(set, fd));
        let want_except = except_in.as_ref().is_some_and(|set| fd_is_set(set, fd));
        if !want_read && !want_write && !want_except {
            continue;
        }

        let file = get_file_like(fd as _)?;
        let state = file.poll()?;
        let mut fd_ready = false;
        if want_read && state.readable {
            fd_set(&mut read_ready, fd);
            fd_ready = true;
        }
        if want_write && state.writable {
            fd_set(&mut write_ready, fd);
            fd_ready = true;
        }
        if want_except {
            // 当前文件抽象没有异常条件，exceptfds 只负责清空非就绪结果。
            let _ = &mut except_ready;
        }
        if fd_ready {
            ready += 1;
        }
    }

    write_fd_set(readfds, &read_ready)?;
    write_fd_set(writefds, &write_ready)?;
    write_fd_set(exceptfds, &except_ready)?;
    Ok(ready)
}

fn clear_select_sets(
    nfds: usize,
    readfds: UserPtr<usize>,
    writefds: UserPtr<usize>,
    exceptfds: UserPtr<usize>,
) -> LinuxResult<()> {
    let words = fd_set_word_count(nfds);
    let empty = alloc::vec![0usize; words];
    write_fd_set(readfds, &empty)?;
    write_fd_set(writefds, &empty)?;
    write_fd_set(exceptfds, &empty)?;
    Ok(())
}

fn fd_set_snapshot_result(
    ptr: UserPtr<usize>,
    words: usize,
) -> LinuxResult<Option<alloc::vec::Vec<usize>>> {
    if ptr.is_null() {
        Ok(None)
    } else {
        Ok(Some(ptr.get_as_mut_slice(words)?.to_vec()))
    }
}

fn write_fd_set(ptr: UserPtr<usize>, words: &[usize]) -> LinuxResult<()> {
    if !ptr.is_null() {
        ptr.get_as_mut_slice(words.len())?.copy_from_slice(words);
    }
    Ok(())
}

