        if cnt == 0 {
            break;
        }

        for ent in dirents.into_iter().take(cnt) {
            let mut dirent_offset = dir.dirent_offset();
            let d_off = *dirent_offset + 1;
            if buffer.write_entry(
                dir.path(),
                ent.entry_type().into(),
                ent.name_as_bytes(),
                d_off,
            ) {
                *dirent_offset = d_off;
            } else {
                *last_dirent = Some(ent);
                break;
            }
        }

        if last_dirent.is_some() {
            break;
        }
    }

    if last_dirent.is_some() && buffer.offset == 0 {
        return Err(LinuxError::EINVAL);
    }
    Ok(buffer.offset as _)
}

