#[derive(Clone, Copy)]
struct FileTimestamps {
    atime: KstatTimestamp,
    mtime: KstatTimestamp,
    ctime: KstatTimestamp,
}

impl FileTimestamps {
    fn from_stat(stat: Kstat) -> Self {
        Self {
            atime: stat.atime(),
            mtime: stat.mtime(),
            ctime: stat.ctime(),
        }
    }
}

struct TimestampOverrides {
    paths: RwLock<BTreeMap<String, FileTimestamps>>,
    fds: RwLock<BTreeMap<c_int, FileTimestamps>>,
}

// 当前 lwext4/axfs 封装没有暴露可写的 atime/mtime/ctime 接口。
// Linux 兼容层先记录 utimensat/futimens 的覆盖值，并在后续 stat/statx/fstat 中返回。
// 这是内存态兼容表，不具备持久化语义，重启或重新挂载后会丢失。
impl TimestampOverrides {
    const fn new() -> Self {
        Self {
            paths: RwLock::new(BTreeMap::new()),
            fds: RwLock::new(BTreeMap::new()),
        }
    }

    fn get_path(&self, path: &str) -> Option<FileTimestamps> {
        self.paths.read().get(path).copied()
    }

    fn set_path(&self, path: String, timestamps: FileTimestamps) {
        self.paths.write().insert(path, timestamps);
    }

    fn get_fd(&self, fd: c_int) -> Option<FileTimestamps> {
        self.fds.read().get(&fd).copied()
    }

    fn set_fd(&self, fd: c_int, timestamps: FileTimestamps) {
        self.fds.write().insert(fd, timestamps);
    }
}

static TIMESTAMP_OVERRIDES: TimestampOverrides = TimestampOverrides::new();

fn apply_timestamps(stat: Kstat, timestamps: FileTimestamps) -> Kstat {
    stat.with_timestamps(timestamps.atime, timestamps.mtime, timestamps.ctime)
}

fn apply_path_timestamp(path: &str, stat: Kstat) -> Kstat {
    TIMESTAMP_OVERRIDES
        .get_path(path)
        .map(|timestamps| apply_timestamps(stat, timestamps))
        .unwrap_or(stat)
}

fn apply_fd_timestamp(fd: c_int, stat: Kstat) -> Kstat {
    TIMESTAMP_OVERRIDES
        .get_fd(fd)
        .map(|timestamps| apply_timestamps(stat, timestamps))
        .unwrap_or(stat)
}

fn path_of_fd(fd: c_int) -> LinuxResult<Option<String>> {
    let file = get_file_like(fd)?;
    if let Ok(file) = file.clone().into_any().downcast::<File>() {
        return Ok(Some(file.path().to_string()));
    }
    if let Ok(dir) = file.into_any().downcast::<Directory>() {
        return Ok(Some(dir.path().to_string()));
    }
    Ok(None)
}

/// 只按真实文件系统路径查询元数据，不处理 BusyBox applet alias。
fn stat_real_path(path: &str) -> LinuxResult<Kstat> {
    let opts = OpenOptions::new().set_read(true);
    match axfs::fops::File::open(path, &opts) {
        Ok(file) => File::new(file, path.into())
            .stat()
            .map(|stat| apply_path_timestamp(path, stat)),
        Err(AxError::IsADirectory) => {
            let dir = axfs::fops::Directory::open_dir(path, &opts)?;
            Directory::new(dir, path.into())
                .stat()
                .map(|stat| apply_path_timestamp(path, stat))
        }
        Err(e) => Err(e.into()),
    }
}

