        AF_INET, IPPROTO_TCP, IPPROTO_UDP, SOCK_DGRAM, SOCK_STREAM, SOL_SOCKET, SO_RCVTIMEO,
        SO_REUSEADDR, SO_SNDTIMEO, sockaddr, socklen_t,
    },
};

