fn socket_from_fd(fd: c_int) -> LinuxResult<alloc::sync::Arc<Socket>> {
    Socket::from_fd(fd)
}

// linux-raw-sys 当前导出的通用常量中没有 SOCK_CLOEXEC，这里按 Linux ABI 固定值定义。
const SOCK_CLOEXEC: u32 = 0o2000000;

fn write_socket_addr(
    socket_addr: SocketAddr,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
) -> LinuxResult {
    if addr.is_null() || addrlen.is_null() {
        return Err(LinuxError::EFAULT);
    }

    let written = socket_addr.write_to_user(addr)?;
    *addrlen.get_as_mut()? = written;
    Ok(())
}

/// 创建 IPv4 TCP/UDP socket。
///
/// 当前实现只支持 libctest 需要的 `AF_INET + SOCK_STREAM/SOCK_DGRAM`。
pub fn sys_socket(domain: c_int, socktype: c_int, protocol: c_int) -> LinuxResult<isize> {
    debug!(
        "sys_socket <= domain: {}, type: {}, protocol: {}",
        domain, socktype, protocol
    );

    let sock_flags = socktype as u32 & (O_NONBLOCK | SOCK_CLOEXEC);
    let sock_kind = socktype as u32 & !(O_NONBLOCK | SOCK_CLOEXEC);

    if domain as u32 != AF_INET {
        return Err(LinuxError::EAFNOSUPPORT);
    }

    let protocol = protocol as u32;
    let socket = if sock_kind == SOCK_DGRAM && (protocol == 0 || protocol == IPPROTO_UDP as u32) {
        Socket::Udp(Mutex::new(axnet::UdpSocket::new()))
    } else if sock_kind == SOCK_STREAM && (protocol == 0 || protocol == IPPROTO_TCP as u32) {
        Socket::Tcp(Mutex::new(axnet::TcpSocket::new()))
    } else {
        return Err(LinuxError::EPROTONOSUPPORT);
    };

    if (sock_flags & O_NONBLOCK) != 0 {
        socket.set_nonblocking(true)?;
    }

    let fd_flags = if (sock_flags & SOCK_CLOEXEC) != 0 {
        linux_raw_sys::general::FD_CLOEXEC
    } else {
        0
    };

    Ok(crate::file::add_file_like_with_flags(alloc::sync::Arc::new(socket), fd_flags)? as _)
}

/// 将本地地址绑定到 socket。
pub fn sys_bind(
    fd: c_int,
    addr: UserConstPtr<sockaddr>,
    addrlen: socklen_t,
) -> LinuxResult<isize> {
    debug!("sys_bind <= fd: {}, addrlen: {}", fd, addrlen);
    let addr = SocketAddr::read_from_user(addr, addrlen)?;
    socket_from_fd(fd)?.bind(addr)?;
    Ok(0)
}

/// 查询 socket 本地地址。
pub fn sys_getsockname(
    fd: c_int,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
) -> LinuxResult<isize> {
    debug!("sys_getsockname <= fd: {}", fd);
    let local = socket_from_fd(fd)?.local_addr()?;
    write_socket_addr(local, addr, addrlen)?;
    Ok(0)
}

/// 设置 socket 选项。
///
/// libctest 主要用它设置超时和地址复用；当前底层 socket 未暴露这些选项，因此只做 fd
/// 校验并接受已知选项。未知选项也暂时返回成功，后续接入完整 socket 选项表时应收紧语义。
pub fn sys_setsockopt(
