    _optlen: socklen_t,
) -> LinuxResult<isize> {
    debug!(
        "sys_setsockopt <= fd: {}, level: {}, optname: {}",
        fd, level, optname
    );
    socket_from_fd(fd)?;

    match (level as u32, optname as u32) {
        (SOL_SOCKET, SO_REUSEADDR) | (SOL_SOCKET, SO_RCVTIMEO) | (SOL_SOCKET, SO_SNDTIMEO) => {
            Ok(0)
        }
        _ => Ok(0),
    }
}

/// 向指定地址发送 UDP 数据。
///
/// TCP 仍通过 `write/send` 路径发送；这里覆盖 `sendto` 对 UDP 和已连接 socket 的常见用法。
pub fn sys_sendto(
    fd: c_int,
    buf: UserConstPtr<u8>,
    len: usize,
    _flags: c_int,
    addr: UserConstPtr<sockaddr>,
    addrlen: socklen_t,
) -> LinuxResult<isize> {
    debug!("sys_sendto <= fd: {}, len: {}, addrlen: {}", fd, len, addrlen);
    let data = buf.get_as_slice(len)?;
    let socket = socket_from_fd(fd)?;

    let sent = if addr.is_null() {
        socket.send(data)?
    } else {
        let addr = SocketAddr::read_from_user(addr, addrlen)?;
        socket.sendto(data, addr)?
    };

    Ok(sent as _)
}

/// 从 socket 接收数据，并可选返回来源地址。
///
/// 对 UDP 返回发送端地址；TCP 没有 datagram peer 地址，因此只返回读取长度。
pub fn sys_recvfrom(
    fd: c_int,
    buf: UserPtr<u8>,
    len: usize,
    _flags: c_int,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
) -> LinuxResult<isize> {
    debug!("sys_recvfrom <= fd: {}, len: {}", fd, len);
    let data = buf.get_as_mut_slice(len)?;
    let (read, peer) = socket_from_fd(fd)?.recvfrom(data)?;
    if !addr.is_null() && !addrlen.is_null() {
        if let Some(peer) = peer {
            write_socket_addr(peer, addr, addrlen)?;
        }
    }
    Ok(read as _)
}

/// 将 TCP socket 切换到监听状态。
pub fn sys_listen(fd: c_int, _backlog: c_int) -> LinuxResult<isize> {
    debug!("sys_listen <= fd: {}", fd);
    socket_from_fd(fd)?.listen()?;
    Ok(0)
}

/// 连接到远端 TCP 地址。
pub fn sys_connect(
    fd: c_int,
    addr: UserConstPtr<sockaddr>,
    addrlen: socklen_t,
) -> LinuxResult<isize> {
    debug!("sys_connect <= fd: {}, addrlen: {}", fd, addrlen);
    let addr = SocketAddr::read_from_user(addr, addrlen)?;
    socket_from_fd(fd)?.connect(addr).map_err(|err| match err {
        // 非阻塞 TCP connect 启动握手后应按 Linux 语义返回 EINPROGRESS。
        LinuxError::EAGAIN => LinuxError::EINPROGRESS,
        err => err,
    })?;
    Ok(0)
}

/// 接受一个 TCP 连接，返回新 fd。
pub fn sys_accept(
    fd: c_int,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
) -> LinuxResult<isize> {
    debug!("sys_accept <= fd: {}", fd);
    let (new_socket, peer_addr) = socket_from_fd(fd)?.accept()?;
    if !addr.is_null() && !addrlen.is_null() {
        if let Some(peer_addr) = peer_addr {
            write_socket_addr(peer_addr, addr, addrlen)?;
        }
    }
    Ok(Socket::Tcp(Mutex::new(new_socket)).add_to_fd_table()? as _)
}

