/// ARCH_PRCTL codes
///
/// It is only avaliable on x86_64, and is not convenient
/// to generate automatically via c_to_rust binding.
#[derive(Debug, Eq, PartialEq, TryFromPrimitive)]
#[repr(i32)]
enum ArchPrctlCode {
    /// Set the GS segment base
    SetGs = 0x1001,
    /// Set the FS segment base
    SetFs = 0x1002,
    /// Get the FS segment base
    GetFs = 0x1003,
    /// Get the GS segment base
    GetGs = 0x1004,
    /// The setting of the flag manipulated by ARCH_SET_CPUID
    GetCpuid = 0x1011,
    /// Enable (addr != 0) or disable (addr == 0) the cpuid instruction for the calling thread.
    SetCpuid = 0x1012,
}

/// To set the clear_child_tid field in the task extended data.
///
/// The set_tid_address() always succeeds
pub fn sys_set_tid_address(clear_child_tid: usize) -> LinuxResult<isize> {
    let curr = current();
    curr.task_ext()
        .thread_data()
        .set_clear_child_tid(clear_child_tid);
    Ok(curr.id().as_u64() as isize)
}

/// 注册当前线程的 robust futex list。
///
/// glibc 会在线程和运行时初始化期间调用该接口。
/// 当前内核还不会在线程退出时遍历该链表，但接受并记录元数据已经足够满足用户态启动兼容。
pub fn sys_set_robust_list(head: usize, len: usize) -> LinuxResult<isize> {
    // Linux 期望这里是 `struct robust_list_head`，大小为三个机器字。
    const ROBUST_LIST_HEAD_SIZE: usize = core::mem::size_of::<usize>() * 3;

    if len != ROBUST_LIST_HEAD_SIZE {
        return Err(LinuxError::EINVAL);
    }

    current()
        .task_ext()
        .thread_data()
        .set_robust_list(head, len);
    Ok(0)
}

/// 查询指定线程注册的 robust futex list。
///
/// `pid == 0` 表示当前线程；非 0 时按 TID 查询。当前实现只返回
/// `set_robust_list` 保存的元数据，线程退出时的 robust futex owner-died
/// 清理仍由后续任务补齐。
pub fn sys_get_robust_list(
    pid: Pid,
    head: UserPtr<usize>,
    len: UserPtr<usize>,
) -> LinuxResult<isize> {
    let thread = if pid == 0 {
        current().task_ext().thread.clone()
    } else {
        get_thread(pid)?
    };
    let (robust_head, robust_len) = thread
        .data::<ThreadData>()
        .map_or((0, core::mem::size_of::<usize>() * 3), |data| {
            data.robust_list()
        });

    *head.get_as_mut()? = robust_head;
    *len.get_as_mut()? = robust_len;
    Ok(0)
}

#[cfg(target_arch = "x86_64")]
pub fn sys_arch_prctl(
    tf: &mut axhal::arch::TrapFrame,
    code: i32,
    addr: usize,
) -> LinuxResult<isize> {
    use crate::ptr::UserPtr;

    let code = ArchPrctlCode::try_from(code).map_err(|_| axerrno::LinuxError::EINVAL)?;
    debug!("sys_arch_prctl: code = {:?}, addr = {:#x}", code, addr);

    match code {
        // According to Linux implementation, SetFs & SetGs does not return
        // error at all
        ArchPrctlCode::GetFs => {
            *UserPtr::from(addr).get_as_mut()? = tf.tls();
            Ok(0)
        }
        ArchPrctlCode::SetFs => {
            tf.set_tls(addr);
            Ok(0)
        }
        ArchPrctlCode::GetGs => {
            *UserPtr::from(addr).get_as_mut()? =
                unsafe { x86::msr::rdmsr(x86::msr::IA32_KERNEL_GSBASE) };
            Ok(0)
        }
        ArchPrctlCode::SetGs => {
            unsafe {
                x86::msr::wrmsr(x86::msr::IA32_KERNEL_GSBASE, addr as _);
            }
            Ok(0)
        }
        ArchPrctlCode::GetCpuid => Ok(0),
        ArchPrctlCode::SetCpuid => Err(axerrno::LinuxError::ENODEV),
    }
}

