pub static HARDLINK_MANAGER: HardlinkManager = HardlinkManager::new();

/// A manager for hardlinks
pub struct HardlinkManager {
    inner: RwLock<LinkManagerInner>,
}
struct LinkManagerInner {
    links: BTreeMap<String, String>,
    ref_counts: BTreeMap<String, usize>,
}

// 关于innner的操作都在atomic_开头的函数中
impl HardlinkManager {
    const fn new() -> Self {
        Self {
            inner: RwLock::new(LinkManagerInner {
                links: BTreeMap::new(),
                ref_counts: BTreeMap::new(),
            }),
        }
    }

    /// 创建链接
    /// 如果目标路径不存在，则返回 `LinkError::NotFound`
    /// 如果目标路径不是文件，则返回 `LinkError::NotFile`
    pub fn create_link(&self, src: &FilePath, dst: &FilePath) -> Result<(), LinkError> {
        if !dst.exists() {
            return Err(LinkError::NotFound);
        }
        if !dst.is_dir() {
            return Err(LinkError::NotFile);
        }

        let mut inner = self.inner.write();
        self.atomic_link_update(&mut inner, src, dst);
        Ok(())
    }

    /// 移除链接
    /// 链接数量为零 或 没有链接时， 删除文件
    /// 如果路径对应的链接不存在 或 路径对应的文件不存在，则返回 `None`
    /// 否则返回链接的目标路径
    pub fn remove_link(&self, src: &FilePath) -> Option<String> {
        let mut inner = self.inner.write();
        self.atomic_link_remove(&mut inner, src).or_else(|| {
            axfs::api::remove_file(src.as_str())
                .ok()
                .map(|_| src.to_string())
        })
    }

    pub fn real_path(&self, path: &str) -> String {
        self.inner
            .read()
            .links
            .get(path)
            .cloned()
            .unwrap_or_else(|| path.to_string())
    }

    pub fn link_count(&self, path: &FilePath) -> usize {

    _mask: u32,
    statxbuf: UserPtr<statx>,
) -> LinuxResult<isize> {
    // `statx()` uses pathname, dirfd, and flags to identify the target
    // file in one of the following ways:

    // An absolute pathname(situation 1)
    //        If pathname begins with a slash, then it is an absolute
    //        pathname that identifies the target file.  In this case,
    //        dirfd is ignored.

    // A relative pathname(situation 2)
    //        If pathname is a string that begins with a character other
    //        than a slash and dirfd is AT_FDCWD, then pathname is a
    //        relative pathname that is interpreted relative to the
    //        process's current working directory.

    // A directory-relative pathname(situation 3)
    //        If pathname is a string that begins with a character other
    //        than a slash and dirfd is a file descriptor that refers to
    //        a directory, then pathname is a relative pathname that is
    //        interpreted relative to the directory referred to by dirfd.
    //        (See openat(2) for an explanation of why this is useful.)

    // By file descriptor(situation 4)
    //        If pathname is an empty string (or NULL since Linux 6.11)
    //        and the AT_EMPTY_PATH flag is specified in flags (see
    //        below), then the target file is the one referred to by the
    //        file descriptor dirfd.

    let path = nullable!(path.get_as_str())?;
    debug!(
        "sys_statx <= dirfd: {}, path: {:?}, flags: {}",
        dirfd, path, flags
    );

    let result: LinuxResult<Kstat> = if path.is_none_or(|s| s.is_empty()) {
        if (flags & AT_EMPTY_PATH) == 0 {
            return Err(LinuxError::ENOENT);
        }
        get_file_like(dirfd)?.stat()
    } else {
        stat_at_dirfd_path(dirfd, path.unwrap_or_default())
    };

    match result {
        Ok(stat) => {
            path_trace::event(
                "statx",
                path,
                format_args!("dirfd={} flags={} result=Ok", dirfd, flags),
            );
            let stat = if path.is_none_or(|s| s.is_empty()) {
                apply_fd_timestamp(dirfd, stat)
            } else {
                stat
            };
            *statxbuf.get_as_mut()? = stat.into();
            Ok(0)
        }
        Err(err) => {
            path_trace::event(
                "statx",
                path,
                format_args!("dirfd={} flags={} result=Err({:?})", dirfd, flags, err),
            );
            Err(err)
        }
    }
}

enum UtimensTarget {
    Path(String, Kstat),
    Fd(c_int, Kstat),
}

impl UtimensTarget {
    fn stat(&self) -> Kstat {
        match self {
            Self::Path(_, stat) | Self::Fd(_, stat) => *stat,
        }
    }

    fn set_timestamps(&self, timestamps: FileTimestamps) {
        match self {
            Self::Path(path, _) => TIMESTAMP_OVERRIDES.set_path(path.clone(), timestamps),
            Self::Fd(fd, _) => {
                TIMESTAMP_OVERRIDES.set_fd(*fd, timestamps);
                // fd 形式的 futimens 也同步一份路径覆盖，保证同一文件随后按路径 stat 能看到更新时间。
                if let Ok(Some(path)) = path_of_fd(*fd) {
                    TIMESTAMP_OVERRIDES.set_path(path, timestamps);
                }
            }
        }
    }
}

fn resolve_utimens_target(
    dirfd: c_int,
    path: Option<&str>,
    flags: u32,
) -> LinuxResult<UtimensTarget> {
    match path {
        None => Ok(UtimensTarget::Fd(
            dirfd,
            apply_fd_timestamp(dirfd, get_file_like(dirfd)?.stat()?),
        )),
        Some("") => {
            if (flags & AT_EMPTY_PATH) == 0 {
                return Err(LinuxError::ENOENT);
            }
            Ok(UtimensTarget::Fd(
                dirfd,
                apply_fd_timestamp(dirfd, get_file_like(dirfd)?.stat()?),
            ))
        }
        Some(path) => {
            let path = handle_file_path(dirfd, path)?;
            let stat = stat_at_path(path.as_str())?;
            Ok(UtimensTarget::Path(path.to_string(), stat))
        }
    }
}

fn current_timestamp() -> KstatTimestamp {
    let now = timespec::from_time_value(wall_time());
    KstatTimestamp::new(now.tv_sec as _, now.tv_nsec as _)
}

fn timestamp_from_timespec(
    input: timespec,
    previous: KstatTimestamp,
    now: KstatTimestamp,
) -> LinuxResult<KstatTimestamp> {
    // Linux 用 tv_nsec 的两个特殊值表达“使用当前时间”和“保持原值”。
    const UTIME_NOW: i64 = 0x3fff_ffff;
    const UTIME_OMIT: i64 = 0x3fff_fffe;

    match input.tv_nsec as i64 {
        UTIME_NOW => Ok(now),
        UTIME_OMIT => Ok(previous),
        nsec if (0..1_000_000_000).contains(&nsec) => {
            Ok(KstatTimestamp::new(input.tv_sec as _, nsec as _))
        }
        _ => Err(LinuxError::EINVAL),
    }
}

/// 更新文件访问时间和修改时间。
///
/// 支持 `futimens()` 使用的空路径 fd 形式，并在 Linux 兼容层记录时间戳覆盖。
pub fn sys_utimensat(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    times: UserConstPtr<timespec>,
    flags: u32,
) -> LinuxResult<isize> {
    let path = nullable!(path.get_as_str())?;
    debug!(
        "sys_utimensat <= dirfd: {}, path: {:?}, flags: {}",
        dirfd, path, flags
    );

    if flags & !(AT_SYMLINK_NOFOLLOW | AT_EMPTY_PATH) != 0 {
        return Err(LinuxError::EINVAL);
    }

    let target = resolve_utimens_target(dirfd, path, flags)?;
    let current = FileTimestamps::from_stat(target.stat());
    let now = current_timestamp();

    let timestamps = if times.is_null() {
        FileTimestamps {
            atime: now,
            mtime: now,
            ctime: now,
        }
    } else {
        let requested = times.get_as_slice(2)?;
        FileTimestamps {
            atime: timestamp_from_timespec(requested[0], current.atime, now)?,
            mtime: timestamp_from_timespec(requested[1], current.mtime, now)?,
            ctime: now,
        }
    };

    target.set_timestamps(timestamps);

    Ok(0)
}

/// 检查路径对应文件是否可访问。
///
/// 当前文件系统权限模型尚不完整，第一版只校验参数和路径存在性。
pub fn sys_faccessat(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    mode: c_int,
    flags: u32,
) -> LinuxResult<isize> {
    let path = nullable!(path.get_as_str())?;
    debug!(
        "sys_faccessat <= dirfd: {}, path: {:?}, mode: {}, flags: {}",
        dirfd, path, mode, flags
    );

    let mode = mode as u32;
    if mode & !(R_OK | W_OK | X_OK) != 0 {
        return Err(LinuxError::EINVAL);
    }
    if flags & !(AT_EACCESS | AT_SYMLINK_NOFOLLOW | AT_EMPTY_PATH) != 0 {
        return Err(LinuxError::EINVAL);
    }

    let result = if path.is_none_or(|s| s.is_empty()) {
        if (flags & AT_EMPTY_PATH) == 0 {
            return Err(LinuxError::ENOENT);
        }
        get_file_like(dirfd)?.stat().map(|_| ())
    } else if mode == F_OK || mode & (R_OK | W_OK | X_OK) != 0 {
        stat_at_dirfd_path(dirfd, path.unwrap_or_default()).map(|_| ())
    } else {
        Ok(())
    };

    match result {
        Ok(()) => {
            path_trace::event(
                "faccessat",
                path,
                format_args!(
                    "dirfd={} mode={} flags={} result=Ok",
                    dirfd, mode, flags
                ),
            );
            Ok(0)
        }
        Err(err) => {
            path_trace::event(
                "faccessat",
                path,
                format_args!(
                    "dirfd={} mode={} flags={} result=Err({:?})",
                    dirfd, mode, flags, err
                ),
            );
            Err(err)
        }
    }
}

//! 文件系统路径 syscall 的开发期追踪工具。
//!
//! 该模块默认关闭，只在编译时设置 `OSKERNEL_TRACE_PATH` 后输出日志；可选的 `OSKERNEL_TRACE_PATH_FILTER` 使用逗号分隔的子串过滤路径。

use core::fmt::Arguments;

fn trace_enabled() -> bool {
    option_env!("OSKERNEL_TRACE_PATH").is_some()
}

fn filter_matches(path: &str) -> bool {
    if let Some(filter) = option_env!("OSKERNEL_TRACE_PATH_FILTER") {
        // 过滤项使用子串匹配，便于临时追踪 `/bin`、`ls` 这类路径片段。
        return filter
            .split(',')
            .map(str::trim)
            .filter(|item| !item.is_empty())
            .any(|item| path.contains(item));
    }

    // 默认过滤只覆盖 BusyBox applet alias 常见路径，避免开启后刷出全部文件系统访问。
    path.contains("/bin") || path.contains("ls")
}

fn should_trace(path: Option<&str>) -> bool {
    if !trace_enabled() {
        return false;
    }

    match path {
        Some(path) => filter_matches(path),
        None => false,
    }
}

/// 记录一次路径相关 syscall 事件。
///
/// `path` 为 `None` 时不输出；`args` 用 `format_args!` 延迟构造，避免未开启 trace 时额外分配字符串。
pub fn event(syscall: &str, path: Option<&str>, args: Arguments<'_>) {
    if should_trace(path) {
        warn!("TRACE path syscall={} path={:?} {}", syscall, path, args);
    }
}

use axhal::time::TimeValue;
use linux_raw_sys::general::{
    __kernel_old_timespec, __kernel_old_timeval, __kernel_sock_timeval, __kernel_timespec,
    timespec, timeval,
};

/// A helper trait for converting from and to `TimeValue`.
pub trait TimeValueLike {
    /// Converts from `TimeValue`.
    fn from_time_value(tv: TimeValue) -> Self;

    /// Converts to `TimeValue`.
    fn to_time_value(self) -> TimeValue;
}

impl TimeValueLike for TimeValue {
    fn from_time_value(tv: TimeValue) -> Self {
        tv
    }

    fn to_time_value(self) -> TimeValue {
        self
    }
}

impl TimeValueLike for timespec {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_nsec: tv.subsec_nanos() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_nsec as u32)
    }
}

impl TimeValueLike for __kernel_timespec {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_nsec: tv.subsec_nanos() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_nsec as u32)
    }
}

impl TimeValueLike for __kernel_old_timespec {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_nsec: tv.subsec_nanos() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_nsec as u32)
    }
}

impl TimeValueLike for timeval {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_usec: tv.subsec_micros() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_usec as u32 * 1000)
    }
}

impl TimeValueLike for __kernel_old_timeval {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_usec: tv.subsec_micros() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_usec as u32 * 1000)
    }
}

impl TimeValueLike for __kernel_sock_timeval {
    fn from_time_value(tv: TimeValue) -> Self {
        Self {
            tv_sec: tv.as_secs() as _,
            tv_usec: tv.subsec_micros() as _,
        }
    }

    fn to_time_value(self) -> TimeValue {
        TimeValue::new(self.tv_sec as u64, self.tv_usec as u32 * 1000)
    }
}
